// src/App.js
import './index.css';
import React, { useState } from 'react';
import {
  BrowserRouter as Router,
  Routes,
  Route,
  Navigate,
  useNavigate
} from 'react-router-dom';

import Header from './components/Header';
import Sidebar from './components/Sidebar';
import TelaPeriodos from './components/TelaPeriodos';
import TelaAlunos from './components/TelaAlunos';
import TelaPacientes from './components/TelaPacientes';
import TelaDisciplinas from './components/TelaDisciplinas';
import TelaAgendamentos from './components/TelaAgendamentos';

import Login from './Login';
import DashboardAluno from './DashboardAluno';
import DashboardRecepcao from './DashboardRecepcao';
import BottomNavBar from './components/BottomNavBar';

import ProtectedRoute from './components/ProtectedRoute';
import { AuthProvider, useAuth } from './context/AuthContext';
import PrintAgendamentos from './pages/PrintAgendamentos';

/**
 * Componente que escolhe qual Dashboard exibir, 
 * baseado em user.role. Se for “recepcao”, exibe DashboardRecepcao; senão, DashboardAluno.
 */
function Dashboards() {
  const { user } = useAuth();

  if (user?.role === 'recepcao') {
    return <DashboardRecepcao />;
  }
  return <DashboardAluno />;
}

/**
 * LayoutInterno: renderiza Header, Sidebar/BottomNavBar e o conteúdo principal
 * com base no menu ativo (Dashboard, Agendar, Disciplinas, Pacientes, Alunos, Períodos).
 */
function LayoutInterno() {
  const [active, setActive] = useState('dashboard');

  function renderConteudo() {
    switch (active) {
      case 'dashboard':
        return <Dashboards />;
      case 'agendar':
        return <TelaAgendamentos />;
      case 'disciplinas':
        return <TelaDisciplinas />;
      case 'pacientes':
        return <TelaPacientes />;
      case 'alunos':
        return <TelaAlunos />;
      case 'periodos':
        return <TelaPeriodos />;
      default:
        return (
          <div>
            <h1 className="text-3xl font-bold mb-6">Página não encontrada</h1>
          </div>
        );
    }
  }

  return (
    <div className="bg-[#ffffff] min-h-screen">
      <Header />
      <div className="flex">
        {/* Sidebar só em MD+ */}
        <div className="hidden md:block">
          <Sidebar active={active} onMenuClick={setActive} />
        </div>
        <main className="flex-1 ml-0 md:ml-64 mt-16 p-8 h-[calc(100vh-64px)] overflow-y-auto">
          <div className="mx-auto">{renderConteudo()}</div>
        </main>
      </div>
      {/* BottomNavBar só em Mobile */}
      <BottomNavBar active={active} onMenuClick={setActive} />
    </div>
  );
}

/**
 * LoginWrapper: usa o hook useAuth para obter a função login,
 * recebe os dados do formulário de Login e redireciona para “/” após login.
 */
function LoginWrapper() {
  const { login } = useAuth();
  const navigate = useNavigate();

  function onLoginHandler(dadosDoLogin) {
    // dadosDoLogin deve ser { token, usuario, role, id }
    login(dadosDoLogin); // agora login({ role, token, id, usuario })
    navigate('/', { replace: true });
  }

  return <Login onLogin={onLoginHandler} />;
}

/**
 * App: envolve tudo em AuthProvider e define as rotas principais:
 * - /login → página pública de login
 * - /print-agendamentos → público para impressão de agendamentos
 * - /* (catch-all) → protegido por ProtectedRoute. Se não estiver logado, redireciona para /login.
 * - qualquer outra rota fora dessas vai para /login
 */
export default function App() {
  return (
    <AuthProvider>
      <Router>
        <Routes>
          {/* Rota pública: Login */}
          <Route path="/login" element={<LoginWrapper />} />

          {/* Rota pública: impressão */}
          <Route path="/print-agendamentos" element={<PrintAgendamentos />} />

          {/* Rotas protegidas (/*) */}
          <Route
            path="/*"
            element={
              <ProtectedRoute>
                <LayoutInterno />
              </ProtectedRoute>
            }
          />

          {/* Qualquer outra rota será redirecionada para /login */}
          <Route path="*" element={<Navigate to="/login" replace />} />
        </Routes>
      </Router>
    </AuthProvider>
  );
}
